--
-- Table structure for table `lab_samples`
--

DROP TABLE IF EXISTS `lab_samples`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_samples` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `lab_request_id` bigint unsigned NOT NULL,
  `sample_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Barcode/unique ID',
  `sample_type` enum('blood','urine','stool','sputum','csf','tissue','swab','fluid','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `collection_date` timestamp NOT NULL,
  `collected_by` bigint unsigned DEFAULT NULL,
  `volume` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `container_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `storage_location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('collected','received','processing','completed','rejected') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'collected',
  `rejection_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `lab_samples_sample_number_unique` (`sample_number`),
  KEY `lab_samples_lab_request_id_foreign` (`lab_request_id`),
  KEY `lab_samples_collected_by_foreign` (`collected_by`),
  KEY `lab_samples_collection_date_index` (`collection_date`),
  KEY `lab_samples_status_index` (`status`),
  CONSTRAINT `lab_samples_collected_by_foreign` FOREIGN KEY (`collected_by`) REFERENCES `staff` (`id`) ON DELETE SET NULL,
  CONSTRAINT `lab_samples_lab_request_id_foreign` FOREIGN KEY (`lab_request_id`) REFERENCES `lab_requests` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=413 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `lab_samples`
--

LOCK TABLES `lab_samples` WRITE;
/*!40000 ALTER TABLE `lab_samples` DISABLE KEYS */;
