  `quality_check_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `quality_checked_at` timestamp NULL DEFAULT NULL,
  `quality_checked_by` bigint unsigned DEFAULT NULL,
