  `status_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `received_date` timestamp NOT NULL,
  `received_by` bigint unsigned DEFAULT NULL,
  `receiving_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `expiry_alert_days` int NOT NULL DEFAULT '180' COMMENT 'Alert X days before expiry',
  `expiry_alert_sent` tinyint(1) NOT NULL DEFAULT '0',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
