--
-- Table structure for table `pharmacy_drug_interactions`
--

DROP TABLE IF EXISTS `pharmacy_drug_interactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pharmacy_drug_interactions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `drug_a_id` bigint unsigned NOT NULL,
  `drug_b_id` bigint unsigned NOT NULL,
  `interaction_severity` enum('minor','moderate','major','contraindicated') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `interaction_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `clinical_effect` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'What happens when combined',
  `mechanism` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'How the interaction occurs',
  `management_recommendation` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `monitoring_parameters` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `evidence_level` enum('theoretical','case_report','study','established') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'theoretical',
  `references` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Scientific references',
  `source` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Database or reference source',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `reviewed_at` timestamp NULL DEFAULT NULL,
  `reviewed_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `pharmacy_drug_interactions_drug_a_id_drug_b_id_unique` (`drug_a_id`,`drug_b_id`),
  KEY `pharmacy_drug_interactions_drug_b_id_foreign` (`drug_b_id`),
  KEY `pharmacy_drug_interactions_reviewed_by_foreign` (`reviewed_by`),
  KEY `pharmacy_drug_interactions_interaction_severity_index` (`interaction_severity`),
  KEY `pharmacy_drug_interactions_is_active_index` (`is_active`),
  CONSTRAINT `pharmacy_drug_interactions_drug_a_id_foreign` FOREIGN KEY (`drug_a_id`) REFERENCES `pharmacy_drugs` (`id`) ON DELETE CASCADE,
  CONSTRAINT `pharmacy_drug_interactions_drug_b_id_foreign` FOREIGN KEY (`drug_b_id`) REFERENCES `pharmacy_drugs` (`id`) ON DELETE CASCADE,
  CONSTRAINT `pharmacy_drug_interactions_reviewed_by_foreign` FOREIGN KEY (`reviewed_by`) REFERENCES `staff` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

