LOCK TABLES `pharmacy_drug_interactions` WRITE;
/*!40000 ALTER TABLE `pharmacy_drug_interactions` DISABLE KEYS */;
/*!40000 ALTER TABLE `pharmacy_drug_interactions` ENABLE KEYS */;
