--
-- Table structure for table `pharmacy_drugs`
--

DROP TABLE IF EXISTS `pharmacy_drugs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pharmacy_drugs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `drug_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'e.g., DRG-0001',
  `generic_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `brand_names` json DEFAULT NULL COMMENT '["Panadol", "Tylenol"]',
  `dosage_form` enum('tablet','capsule','syrup','suspension','injection','cream','ointment','gel','drops','inhaler','suppository','patch','powder','solution','lotion','spray') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `strength` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'e.g., 500mg, 5mg/ml',
  `route_of_administration` enum('oral','iv','im','sc','topical','inhalation','rectal','vaginal','ophthalmic','otic','nasal','transdermal') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `drug_category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Analgesic, Antibiotic, etc.',
  `therapeutic_class` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `controlled_substance` tinyint(1) NOT NULL DEFAULT '0',
  `schedule` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Schedule I-V for controlled substances',
  `requires_prescription` tinyint(1) NOT NULL DEFAULT '1',
  `storage_conditions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `storage_temp_min` decimal(5,2) DEFAULT NULL,
  `storage_temp_max` decimal(5,2) DEFAULT NULL,
  `indications` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `contraindications` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `side_effects` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `drug_interactions` json DEFAULT NULL COMMENT '[{"drug_id": 123, "severity": "major"}]',
  `warnings` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `precautions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `pregnancy_category` enum('A','B','C','D','X','N/A') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'N/A',
  `safe_in_pregnancy` tinyint(1) NOT NULL DEFAULT '0',
  `safe_in_lactation` tinyint(1) NOT NULL DEFAULT '0',
  `pediatric_use` tinyint(1) NOT NULL DEFAULT '1',
  `geriatric_considerations` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `renal_dosing` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `hepatic_dosing` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `manufacturer` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `active_ingredient` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `inactive_ingredients` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `unit_of_measure` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `default_unit_price` decimal(10,2) NOT NULL DEFAULT '0.00',
  `current_stock` int NOT NULL DEFAULT '0',
  `reorder_level` int NOT NULL DEFAULT '50' COMMENT 'Alert when stock below this',
  `reorder_quantity` int NOT NULL DEFAULT '100' COMMENT 'Suggested reorder quantity',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `deactivation_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `pharmacy_drugs_drug_code_unique` (`drug_code`),
  KEY `pharmacy_drugs_created_by_foreign` (`created_by`),
  KEY `pharmacy_drugs_updated_by_foreign` (`updated_by`),
  KEY `pharmacy_drugs_generic_name_index` (`generic_name`),
  KEY `pharmacy_drugs_drug_category_index` (`drug_category`),
